solution_code:
#include <iostream>
#include <iomanip>

int main()
{
    const double km_per_mile{ 1.60934 };

    int miles{};
    std::cin >> miles;

    double km{ miles * km_per_mile };
    double m{ km * 1000.0 };

    std::cout << "kilometers: " << std::fixed << std::setprecision(3) << km << "\n";
    std::cout << "meters: " << std::fixed << std::setprecision(1) << m << "\n";

    return 0;
}

