solution_code:
#include <iostream>

int main()
{
    const int perimeter_factor{ 2 };

    int width{};
    int height{};
    std::cin >> width >> height;

    int area = width * height;
    int perimeter = perimeter_factor * (width + height);

    std::cout << "area: " << area << "\n";
    std::cout << "perimeter: " << perimeter << "\n";
    return 0;
}
